"""Byte templates captured from a genuine iPhone Live Photo (wallpaper).

These reproduce the per-frame ``live-photo-info`` metadata track that iOS
requires before a Live Photo can be used as a wallpaper.  All frames share
the same motion blob, which iOS accepts.
"""

import base64

LIVE_PHOTO_INFO_TIMESCALE = 60000
MOVIE_TIMESCALE_REF = 44100

_STSD_B64 = ""
_SAMPLE_B64 = "AAAAkAAAAAEDAAAAvcNtPOO1622AAAAAe4CtQlotZEEKCMs+f+6mvXnp9j8AAIBABAD/AAAAAAAAAAAAAAAAAAAAAAAAAAAABwAAAFJehz7mblK/GypqxNN4Yr92HtI93j+OwxP1Lzmy8EQ5/zCdvxoX8e0bBwAAIGeW7RsHAAAAAAAAAAAAAAAAAAAAAAAA"

LIVE_PHOTO_INFO_STSD = base64.b64decode(_STSD_B64)
LIVE_PHOTO_INFO_SAMPLE = base64.b64decode(_SAMPLE_B64)
